documents:
{{- range $inv := .Invoices }}

        {{xmlEscape $inv.ID}}
        {{if $inv.ToCompany}}{{xmlEscape $inv.ToCompany.Street}}, {{xmlEscape $inv.ToCompany.City}}, {{xmlEscape $inv.ToCompany.Country}}{{end}}
        {{if $inv.ToCompany}}{{xmlEscape $inv.ToCompany.Code}}{{end}}
        {{if $inv.ToCompany}}{{xmlEscape $inv.ToCompany.Code}}{{end}}
        {{if $inv.ToCompany}}{{xmlEscape $inv.ToCompany.Title}}{{end}}
        {{if $inv.ToCompany}}{{xmlEscape $inv.ToCompany.VATIdentificationNumber}}{{end}}
        {{xmlEscape $inv.Currency}}
        {{formatDate $inv.IssueDate "2006-01-02"}}
        {{xmlEscape $inv.SeriesAndNumber}}
        {{xmlEscape $inv.Filename}}
{{- range $item := $inv.Items }}


            {{formatFloat (div $item.AmountWithoutVat $item.Quantity) 4}}
            {{formatFloat $item.Quantity 4}}
            {{formatFloat $item.AmountWithoutVat 2}}
            {{formatFloat $item.AmountWithVat 2}}
            vnt
            {{formatFloat $item.VatAmount 2}}
            PVM1
            21

{{- end }}
        {{formatDate $.Now "2006-01-02"}}
        {{if $inv.FromCompany}}{{xmlEscape $inv.FromCompany.Street}}, {{xmlEscape $inv.FromCompany.City}}, {{xmlEscape $inv.FromCompany.Country}}{{end}}
        {{if $inv.FromCompany}}{{xmlEscape $inv.FromCompany.Code}}{{end}}
        {{if $inv.FromCompany}}{{xmlEscape $inv.FromCompany.BankAccount}}{{end}}
        {{if $inv.FromCompany}}{{xmlEscape $inv.FromCompany.Code}}{{end}}
        {{if $inv.FromCompany}}{{xmlEscape $inv.FromCompany.Title}}{{end}}
        {{if $inv.FromCompany}}{{xmlEscape $inv.FromCompany.VATIdentificationNumber}}{{end}}
        {{formatFloat $inv.AmountWithoutVat 2}}
        {{formatFloat $inv.AmountWithVat 2}}
        {{xmlEscape $inv.URL}}
        {{formatFloat $inv.VatAmount 2}}

{{- end }}
